import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class SecureCommandExecution {

    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a website to ping: ");
            String website = br.readLine();

            // Sanitize the input to prevent command injection
            if (!website.matches("[a-zA-Z0-9.-]+")) {
                System.out.println("Invalid website format. Please enter a valid website.");
                return;
            }

            // Build and execute the command using ProcessBuilder
            ProcessBuilder processBuilder = new ProcessBuilder("ping", website);
            Process process = processBuilder.start();

            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

